 1	import React, { FC } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { V1Template } from '@kubevirt-ui/kubevirt-api/console';
 5	import SidebarEditorSwitch from '@kubevirt-utils/components/SidebarEditor/SidebarEditorSwitch';
 6	import { VirtualMachineDetailsTab } from '@kubevirt-utils/constants/tabs-constants';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { useLastNamespacePath } from '@kubevirt-utils/hooks/useLastNamespacePath';
 9	import { isDeprecatedTemplate } from '@kubevirt-utils/resources/template';
10	import {
11	  Breadcrumb,
12	  BreadcrumbItem,
13	  Button,
14	  Label,
15	  Split,
16	  SplitItem,
17	  Title,
18	} from '@patternfly/react-core';
19	
20	import VirtualMachineTemplatesActions from '../actions/VirtualMachineTemplatesActions';
21	
22	import useEditTemplateAccessReview from './hooks/useIsTemplateEditable';
23	import CommonTemplateAlert from './CommonTemplateAlert';
24	import NoPermissionTemplateAlert from './NoPermissionTemplateAlert';
25	
26	type TemplatePageTitleTitleProps = {
27	  template: V1Template;
28	};
29	
30	const TemplatePageTitle: FC<TemplatePageTitleTitleProps> = ({ template }) => {
31	  const { t } = useKubevirtTranslation();
32	  const navigate = useNavigate();
33	  const location = useLocation();
34	  const lastNamespacePath = useLastNamespacePath();
35	  const { hasEditPermission, isCommonTemplate } = useEditTemplateAccessReview(template);
36	
37	  const isSidebarEditorDisplayed = !location.pathname.includes(
38	    `/templates/${template?.metadata?.name}/${VirtualMachineDetailsTab.YAML}`,
39	  );
40	
41	  return (
42	    <div className="pf-v6-c-page__main-breadcrumb TemplatePageTitle">
43	      <Breadcrumb>
44	        <BreadcrumbItem>
45	          <Button
46	            isInline
47	            onClick={() => navigate(`/k8s/${lastNamespacePath}/templates`)}
48	            variant="link"
49	          >
50	            {t('Templates')}
51	          </Button>
52	        </BreadcrumbItem>
53	        <BreadcrumbItem>{template?.metadata?.name}</BreadcrumbItem>
54	      </Breadcrumb>
55	
56	      <Title className="co-m-pane__heading" headingLevel="h1">
57	        <span className="co-resource-item__resource-name">
58	          <span className="co-m-resource-icon co-m-resource-icon--lg">T</span>
59	          <span className="co-resource-item__resource-name">
60	            {template?.metadata?.name}{' '}
61	            {isDeprecatedTemplate(template) && <Label isCompact>{t('Deprecated')}</Label>}
62	          </span>
63	        </span>
64	        <Split hasGutter>
65	          {isSidebarEditorDisplayed && (
66	            <SplitItem>
67	              <SidebarEditorSwitch />
68	            </SplitItem>
69	          )}
70	          <SplitItem>
71	            <VirtualMachineTemplatesActions template={template} />
72	          </SplitItem>
73	        </Split>
74	      </Title>
75	      {isCommonTemplate && <CommonTemplateAlert template={template} />}
76	      {!isCommonTemplate && !hasEditPermission && <NoPermissionTemplateAlert />}
77	    </div>
78	  );
79	};
80	
81	export default TemplatePageTitle;

